function roll(sides) {
    return Math.ceil(Math.random() * sides);
}

function pick(table) {
    const r = roll(table.length);
    return { roll: r, result: table[r - 1] };
}

function pickWeighted(table, sides = 100) {
    const r = roll(sides);
    const result = table.find(row => r >= row.min && r <= row.max).result;
    return { roll: r, result };
}

